function tryParseJson(value: string | null) {
    if (!value) return null;
    try {
        return JSON.parse(value);
    } catch {
        return null;
    }
}

function stripHtml(html: string) {
    return html
        .replace(/<script[\s\S]*?<\/script>/gi, "")
        .replace(/<style[\s\S]*?<\/style>/gi, "")
        .replace(/<[^>]+>/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

function formatDonationEvalBlock(obj: unknown): string {
    if (obj == null) return "";
    if (typeof obj === "string") return obj.trim();
    try {
        return JSON.stringify(obj, null, 2);
    } catch {
        return String(obj);
    }
}

function filterJobDataByRuntimeFields(data: Record<string, unknown>) {
    try {
        const fields = (prisma as any)?._runtimeDataModel?.models?.Job?.fields;
        if (!Array.isArray(fields)) return data;
        const allowed = new Set(
            fields
                .map((f: any) => (f && typeof f.name === "string" ? f.name : ""))
                .filter(Boolean)
        );
        return Object.fromEntries(
            Object.entries(data).filter(([k]) => allowed.has(k))
        );
    } catch {
        return data;
    }
}

function extractImageUrlsFromResult(result: unknown): string[] {
    const urls = new Set<string>();

    function walk(value: unknown) {
        if (!value) return;

        if (typeof value === "string") {
            const lower = value.toLowerCase();
            if (
                (value.startsWith("http://") || value.startsWith("https://")) &&
                (lower.includes(".png") ||
                    lower.includes(".jpg") ||
                    lower.includes(".jpeg") ||
                    lower.includes(".webp") ||
                    lower.includes("image"))
            ) {
                urls.add(value);
            }
            return;
        }

        if (Array.isArray(value)) {
            for (const item of value) walk(item);
            return;
        }

        if (typeof value === "object") {
            for (const nested of Object.values(value as Record<string, unknown>)) {
                walk(nested);
            }
        }
    }

    walk(result);
    return Array.from(urls);
}

function extractLatestClaudeDiagnostics(
    claudeOutput: string | null
): ClaudeParseDiagnostics | null {
    const text = claudeOutput || "";
    const startMarker = "__CLAUDE_PARSE_DIAGNOSTICS__";
    const endMarker = "__END_CLAUDE_PARSE_DIAGNOSTICS__";

    const start = text.lastIndexOf(startMarker);
    if (start === -1) return null;

    const afterStart = start + startMarker.length;
    const end = text.indexOf(endMarker, afterStart);
    if (end === -1) return null;

    const jsonText = text.slice(afterStart, end).trim();
    const parsed = tryParseJson(jsonText);
    return parsed && typeof parsed === "object"
        ? (parsed as ClaudeParseDiagnostics)
        : null;
}

// --- Donation step actions (donation-only) ---
async function analyzeDonationFundraiser(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    if (!jobId) throw new Error("Missing jobId");

    const job = await prisma.job.findUnique({ where: { id: jobId } });
    if (!job) throw new Error("Job not found");
    if (job.campaignType !== "donation") redirect(`/jobs/${jobId}`);

    try {
        const scraped = await scrapeUrlToHtml(job.url);
        const rawText = stripHtml(scraped.html || "").slice(0, 16000);
        const pageEval = await evaluateDonationPageFromScrape({
            fundraiserUrl: job.url,
            scrapedText: rawText,
        });

        await persistDonationPageEvalAndAutoStoryEval({
            jobId,
            pageEval: pageEval as Record<string, unknown>,
            rawText,
            filterJobData: filterJobDataByRuntimeFields,
            jobRow: {
                campaign_type: job.campaign_type,
                subject_name: job.subject_name,
                urgency_level: job.urgency_level,
                emotional_hook: job.emotional_hook,
            },
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        const fallbackEval = {
            subjectName: "Fundraiser",
            whatHappened:
                "Unable to auto-extract from URL. Please provide backstory manually.",
            whyFundingIsNeeded: "User-provided details required.",
            urgencyLevel: "general",
            keyEmotionalHooks: [
                "Human impact",
                "Urgent support needed",
                "Direct call for help",
            ],
            usefulPhrases: ["Help now", "Support this fundraiser"],
            draftBackstory: "",
            warning:
                "Automatic page analysis failed in retry. Continue with manual backstory.",
        };

        const prevRow = await prisma.job.findUnique({
            where: { id: jobId },
            select: { claudeOutput: true },
        });
        const mergedClaude = mergeDonationWizardSnapshotIntoClaudeOutput(
            prevRow?.claudeOutput,
            {
                pageEvaluation: fallbackEval,
                backstorySummary: "",
                pageEvaluationRetryError: message,
            }
        );

        await prisma.job.update({
            where: { id: jobId },
            data: filterJobDataByRuntimeFields({
                donationPageEvaluation: JSON.stringify(fallbackEval),
                status: "donation_page_evaluated",
                claudeOutput: mergedClaude,
            }) as any,
        });
    }

    redirect(`/jobs/${jobId}`);
}

async function evaluateDonationStory(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const backstory = String(formData.get("backstory") || "").trim();
    if (!jobId) throw new Error("Missing jobId");
    if (!backstory) throw new Error("Backstory is required.");

    const job = await prisma.job.findUnique({ where: { id: jobId } });
    if (!job) throw new Error("Job not found");

    const evalResult = await evaluateDonationBackstory({
        campaignType: job.campaign_type || "FAMILY CRISIS",
        subjectName: job.subject_name || "Fundraiser",
        urgencyLevel: job.urgency_level || "general",
        emotionalHook: job.emotional_hook || undefined,
        backstorySummary: backstory,
    });

    const prevOut = await prisma.job.findUnique({
        where: { id: jobId },
        select: { claudeOutput: true },
    });
    const mergedClaude = mergeDonationWizardSnapshotIntoClaudeOutput(
        prevOut?.claudeOutput,
        {
            storyEvaluation: evalResult as Record<string, unknown>,
            backstorySummary: backstory,
        }
    );

    await prisma.job.update({
        where: { id: jobId },
        data: filterJobDataByRuntimeFields({
            backstory_summary: backstory,
            physical_description: backstory,
            injury_or_medical_details: backstory,
            donationBackstoryEvaluation: JSON.stringify(evalResult),
            claudeOutput: mergedClaude,
            status: "donation_story_evaluated",
        }) as any,
    });

    redirect(`/jobs/${jobId}`);
}

async function evaluateDonationImages(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    if (!jobId) throw new Error("Missing jobId");

    const rawFiles = formData.getAll("reference_images");
    const files = rawFiles.filter(
        (item): item is File =>
            !!item &&
            typeof (item as any).size === "number" &&
            (item as any).size > 0
    );
    const imageDescriptions = formData
        .getAll("reference_image_descriptions[]")
        .map((v) => String(v).trim());

    async function readClaudeOutput() {
        const row = await prisma.job.findUnique({
            where: { id: jobId },
            select: { claudeOutput: true },
        });
        return row?.claudeOutput ?? null;
    }

    if (files.length > 0) {
        try {
            const uploaded = await uploadReferenceFilesToKie(files.slice(0, 6));
            await prisma.referenceAsset.deleteMany({
                where: { jobId, adId: null },
            });
            await prisma.referenceAsset.createMany({
                data: uploaded.map((file) => ({
                    jobId,
                    adId: null,
                    filePath: file.filePath,
                    originalName: file.originalName,
                    mimeType: file.mimeType,
                })),
            });
        } catch (uploadErr) {
            const msg =
                uploadErr instanceof Error
                    ? uploadErr.message
                    : String(uploadErr);
            const mergedClaude = mergeDonationWizardSnapshotIntoClaudeOutput(
                await readClaudeOutput(),
                {
                    referenceEvaluationError: `Image upload failed: ${msg}`,
                }
            );
            await prisma.job.update({
                where: { id: jobId },
                data: filterJobDataByRuntimeFields({
                    claudeOutput: mergedClaude,
                }) as any,
            });
            redirect(`/jobs/${jobId}`);
        }
    }

    const refs = await prisma.referenceAsset.findMany({
        where: { jobId, adId: null },
        orderBy: { createdAt: "asc" },
        select: { filePath: true, originalName: true },
    });

    if (refs.length === 0) {
        const mergedClaude = mergeDonationWizardSnapshotIntoClaudeOutput(
            await readClaudeOutput(),
            {
                referenceEvaluationError:
                    "Add at least one reference image, then try Evaluate Images again.",
            }
        );
        await prisma.job.update({
            where: { id: jobId },
            data: filterJobDataByRuntimeFields({
                claudeOutput: mergedClaude,
            }) as any,
        });
        redirect(`/jobs/${jobId}`);
    }

    const referenceDescriptions = refs.map((r, idx) => ({
        index: idx,
        description: imageDescriptions[idx] || r.originalName || "",
    }));

    const job = await prisma.job.findUnique({ where: { id: jobId } });
    if (!job) throw new Error("Job not found");

    let evalResult: Record<string, unknown>;
    let evalOk = true;
    try {
        evalResult = (await evaluateDonationReferences({
            campaignType: job.campaign_type || "FAMILY CRISIS",
            referenceDescriptions,
            referenceImageUrls: refs.map((r) => r.filePath),
            physicalDescription:
                job.physical_description || job.backstory_summary || "",
            injuryOrMedicalDetails:
                job.injury_or_medical_details || job.backstory_summary || "",
        })) as Record<string, unknown>;
    } catch (claudeErr) {
        evalOk = false;
        const msg =
            claudeErr instanceof Error
                ? claudeErr.message
                : String(claudeErr);
        evalResult = {
            imagesSummary: "Reference image evaluation failed (see error).",
            error: msg,
        };
    }

    const mergedClaude = mergeDonationWizardSnapshotIntoClaudeOutput(
        await readClaudeOutput(),
        evalOk
            ? {
                  referenceEvaluation: evalResult,
                  referenceEvaluationError: null,
                  referenceEvaluationApiFailed: null,
              }
            : {
                  referenceEvaluation: evalResult,
                  referenceEvaluationApiFailed: true,
              }
    );

    await prisma.job.update({
        where: { id: jobId },
        data: filterJobDataByRuntimeFields({
            donationReferenceEvaluation: JSON.stringify(evalResult),
            claudeOutput: mergedClaude,
            status: evalOk ? "donation_images_evaluated" : job.status,
        }) as any,
    });

    redirect(`/jobs/${jobId}`);
}

async function goToDonationAdBuilder(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    if (!jobId) throw new Error("Missing jobId");

    const job = await prisma.job.findUnique({
        where: { id: jobId },
        select: {
            campaignType: true,
            claudeOutput: true,
            donationBackstoryEvaluation: true,
            donationReferenceEvaluation: true,
            donationPageEvaluation: true,
        },
    });
    if (!job) throw new Error("Job not found");

    if (job.campaignType !== "donation") {
        redirect(`/jobs/${jobId}`);
    }

    const { backstoryEvaluation, referenceEvaluation } =
        resolveDonationEvaluations(job);
    if (
        Object.keys(backstoryEvaluation).length === 0 ||
        Object.keys(referenceEvaluation).length === 0
    ) {
        redirect(`/jobs/${jobId}`);
    }

    await prisma.job.update({
        where: { id: jobId },
        data: { status: "donation_build" },
    });

    redirect(`/jobs/${jobId}`);
}

async function generateFundraiserFiveAds(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    if (!jobId) throw new Error("Missing jobId");

    const selectedReferenceIds = Array.from(
        new Set(
            formData
                .getAll("selectedReferenceIds")
                .map((v) => String(v).trim())
                .filter(Boolean)
        )
    );

    const job = await prisma.job.findUnique({ where: { id: jobId } });
    if (!job) throw new Error("Job not found");
    if (job.campaignType !== "donation") redirect(`/jobs/${jobId}`);

    const { pageEvaluation, backstoryEvaluation, referenceEvaluation } =
        resolveDonationEvaluations(job);

    if (
        Object.keys(backstoryEvaluation).length === 0 ||
        Object.keys(referenceEvaluation).length === 0
    ) {
        throw new Error("Run donation evaluation first.");
    }

    const jobSharedRefsAll = await prisma.referenceAsset.findMany({
        where: { jobId, adId: null },
        orderBy: { createdAt: "asc" },
        select: {
            id: true,
            filePath: true,
            originalName: true,
            mimeType: true,
        },
    });
    const jobSharedRefs =
        selectedReferenceIds.length > 0
            ? jobSharedRefsAll.filter((ref) =>
                  selectedReferenceIds.includes(String(ref.id))
              )
            : jobSharedRefsAll;
    const referenceImageUrls = jobSharedRefs
        .map((r) => r.filePath)
        .filter(Boolean);

    const rnd = Math.random;
    const brainRow =
        (await getFundraiserCreativeBrain()) ?? {
            previousWinningPrompts: "",
            anglesList: "",
            additionalInfo: "",
        };
    const plans = planFundraiserBatchOfFive(brainRow.anglesList, rnd);
    const winningSeeds = pickRandomWinningPromptSeeds(
        brainRow.previousWinningPrompts,
        5,
        rnd
    );
    const brainStaticPreamble = buildBrainStaticPreamble(brainRow);
    const slots = plans.map((p, i) => ({
        slotIndex: p.slotIndex,
        styleTemplateId: p.styleTemplateId,
        templateLabel: donationStyleTemplateLabel(p.styleTemplateId),
        selectedAngle: p.angleLine,
        keyedBrainInstructions: buildBrainKeyedInstructions(
            brainRow,
            p.activeBrainKeys
        ),
        winningPromptSeed: winningSeeds[i] || undefined,
    }));

    const planForHistory = plans.map((p, i) => ({
        slotIndex: p.slotIndex,
        styleTemplateId: p.styleTemplateId,
        templateLabel: donationStyleTemplateLabel(p.styleTemplateId),
        angleLine: p.angleLine,
        varKeys: [...p.varKeys],
        winningPromptSeed: winningSeeds[i] || undefined,
    }));

    const priorBatchesSummary = formatBatchHistoryForPrompt(
        parseFundraiserBatchHistory(job.fundraiserBatchHistory)
    );

    const platforms = String(job.platform || "")
        .split(",")
        .map((s) => s.trim())
        .filter(Boolean);

    const adJson = await generateDonationFundraiserBatchFive({
        campaignType: job.campaign_type || "",
        subjectName: job.subject_name || "",
        subjectType: job.subject_type || "",
        speciesBreedAge: job.species_breed_age || "",
        physicalDescription: job.physical_description || "",
        injuryOrMedicalDetails: job.injury_or_medical_details || "",
        backstorySummary: job.backstory_summary || "",
        urgencyLevel: job.urgency_level || "",
        fundraiserGoalAmount: job.fundraiser_goal_amount || undefined,
        emotionalHook: job.emotional_hook || undefined,
        companionOrFamilyDetail: job.companion_or_family_detail || undefined,
        beforeDetail: job.before_detail || undefined,
        platforms: platforms.length ? platforms.join(", ") : job.platform || "",
        pageEvaluation,
        backstoryEvaluation,
        referenceEvaluation,
        referenceImageUrls,
        brainStaticPreamble,
        priorBatchesSummary,
        slots,
    });

    const parsed = parseValidateAndNormalizeClaudeAds(
        JSON.stringify(adJson),
        5
    );

    if (!parsed.ok || parsed.ads.length !== 5) {
        await prisma.job.update({
            where: { id: jobId },
            data: {
                status: "donation_ad_error",
                claudeOutput: JSON.stringify(
                    {
                        error: parsed.ok
                            ? `Expected 5 ads, got ${parsed.ads.length}`
                            : parsed.diagnostics.error,
                    },
                    null,
                    2
                ),
            },
        });
        redirect(`/jobs/${jobId}`);
    }

    const maxAdNumber = await prisma.ad.findFirst({
        where: { jobId },
        orderBy: { adNumber: "desc" },
        select: { adNumber: true },
    });
    let nextAdNumber = (maxAdNumber?.adNumber ?? 0) + 1;

    const createdIds: string[] = [];
    for (let i = 0; i < 5; i++) {
        const num = nextAdNumber++;
        const ad = await prisma.ad.create({
            data: {
                jobId,
                adNumber: num,
                title: `Ad ${num}`,
                sourceBlock: JSON.stringify(parsed.ads[i], null, 2),
                editedPrompt: String(parsed.ads[i]!.visualPrompt || "").trim(),
                status: "ready",
            },
        });
        createdIds.push(ad.id);
    }

    if (jobSharedRefs.length > 0) {
        for (const adId of createdIds) {
            await prisma.referenceAsset.createMany({
                data: jobSharedRefs.map((ref) => ({
                    jobId,
                    adId,
                    filePath: ref.filePath,
                    originalName: ref.originalName,
                    mimeType: ref.mimeType,
                })),
            });
        }
    }

    const summaryAds = parsed.ads.map((a, i) => ({
        hook: typeof a.hook === "string" ? a.hook : undefined,
        angle: typeof a.angle === "string" ? a.angle : undefined,
        templateId: plans[i]?.styleTemplateId,
    }));

    await prisma.job.update({
        where: { id: jobId },
        data: {
            fundraiserBatchHistory: appendFundraiserBatchHistory(
                job.fundraiserBatchHistory,
                summaryAds,
                planForHistory
            ),
        },
    });

    redirect(`/jobs/${jobId}`);
}

// --- Ad editing stage ---
async function saveAdPromptAndReferences(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const adId = formData.get("adId")?.toString();
    const editedPrompt = formData.get("editedPrompt")?.toString() || "";

    if (!jobId || !adId) throw new Error("Missing jobId or adId");

    await prisma.ad.update({
        where: { id: adId },
        data: { editedPrompt },
    });

    redirect(`/jobs/${jobId}`);
}

// --- Ad variation stage (append sibling variation tabs) ---
async function generateAdVariations(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const baseAdId = formData.get("adId")?.toString();
    const variationCountRaw = formData.get("variationCount")?.toString();
    let variationInstruction = String(
        formData.get("variationInstruction") || ""
    ).trim();

    if (!jobId || !baseAdId) throw new Error("Missing jobId or adId");

    const variationCount = Number(variationCountRaw);

    const job = await prisma.job.findUnique({ where: { id: jobId } });
    if (!job) throw new Error("Job not found");

    // Donation variations: translate UI checkboxes into a compact instruction.
    const donationVariationParts: string[] = [];
    const vHigherAggression = !!formData.get(
        "variationHigherAggression"
    );
    const vLowerAggression = !!formData.get("variationLowerAggression");
    const vAddText = !!formData.get("variationAddText");
    const vStrongerCTA = !!formData.get("variationStrongerCTA");
    const vHigherQuality = !!formData.get("variationHigherQuality");
    const vBeforeAfter = !!formData.get("variationBeforeAfter");

    if (job.campaignType === "donation") {
        if (vHigherAggression) donationVariationParts.push("higher aggression");
        if (vLowerAggression) donationVariationParts.push("lower aggression");
        if (vAddText) donationVariationParts.push("add text");
        if (vStrongerCTA) donationVariationParts.push("stronger CTA");
        if (vHigherQuality) donationVariationParts.push("higher quality");
        if (vBeforeAfter) donationVariationParts.push("before/after framing");

        if (donationVariationParts.length) {
            const extra = donationVariationParts.join(", ");
            variationInstruction = variationInstruction
                ? `${variationInstruction}; ${extra}`
                : extra;
        }
    }

    const safeCount =
        job.campaignType === "donation"
            ? 1
            : Number.isFinite(variationCount) && variationCount >= 3
              ? Math.max(3, Math.min(5, Math.floor(variationCount)))
              : 4;

    const baseAd = await prisma.ad.findUnique({ where: { id: baseAdId } });
    if (!baseAd?.sourceBlock)
        throw new Error("Base ad missing sourceBlock");

    type BaseAdPayload = {
        angle?: unknown;
        hook?: unknown;
        primaryText?: unknown;
        headline?: unknown;
        cta?: unknown;
        visualPrompt?: unknown;
    };

    const baseSource = tryParseJson(baseAd.sourceBlock);
    const basePayload = baseSource as BaseAdPayload | null;

    if (
        !basePayload ||
        typeof basePayload !== "object" ||
        typeof basePayload.angle !== "string" ||
        typeof basePayload.hook !== "string" ||
        typeof basePayload.primaryText !== "string" ||
        typeof basePayload.headline !== "string" ||
        typeof basePayload.cta !== "string" ||
        typeof basePayload.visualPrompt !== "string"
    ) {
        // If the base ad isn't in the expected format, fail gracefully by not generating variations.
        redirect(`/jobs/${jobId}`);
    }

    const brainForVariations = await getFundraiserCreativeBrain();
    const variationVarKeys = variationCheckboxesToVarKeys({
        higherAggression: vHigherAggression,
        lowerAggression: vLowerAggression,
        addText: vAddText,
        strongerCTA: vStrongerCTA,
        higherQuality: vHigherQuality,
        beforeAfter: vBeforeAfter,
    });
    const creativeBrainSectionForVariations =
        job.campaignType === "donation"
            ? buildBrainPromptSection(brainForVariations, variationVarKeys)
            : undefined;

    const variationsRaw = await generateAdVariationsFromBaseAd({
        baseAd: {
            angle: basePayload.angle,
            hook: basePayload.hook,
            primaryText: basePayload.primaryText,
            headline: basePayload.headline,
            cta: basePayload.cta,
            visualPrompt: basePayload.visualPrompt,
        },
        campaignType: job.campaignType === "donation" ? "donation" : "product",
        requestedVariations: safeCount,
        creativeMode: job.creativeMode || "Mix",
        adMixStrategy: job.adMixStrategy || "Even Mix",
        strictlyFollowSelectedAngles: job.strictlyFollowSelectedAngles ?? false,
        includeExperimentalAds: job.includeExperimentalAds ?? false,
        variationInstruction,
        creativeBrainSection: creativeBrainSectionForVariations,
    });

    const parsedResult = parseValidateAndNormalizeClaudeAds(
        variationsRaw,
        safeCount
    );

    if (!parsedResult.ok) {
        redirect(`/jobs/${jobId}`);
    }

    if (parsedResult.ads.length === 0) {
        redirect(`/jobs/${jobId}`);
    }

    const maxAdNumber = await prisma.ad.findFirst({
        where: { jobId },
        orderBy: { adNumber: "desc" },
        select: { adNumber: true },
    });

    const startAdNumber = (maxAdNumber?.adNumber ?? 0) + 1;

    await prisma.ad.createMany({
        data: parsedResult.ads.map((ad, i) => ({
            jobId,
            adNumber: startAdNumber + i,
            title: `Variation ${i + 1}`,
            sourceBlock: JSON.stringify(ad, null, 2),
            editedPrompt: String(ad.visualPrompt || "").trim(),
            status: "ready",
            parentAdId: baseAdId,
        })),
    });

    // Donation-only: ensure variations reuse the same reference images
    // as the base ad by copying referenceAsset rows to the new adId.
    if (job.campaignType === "donation") {
        const baseAdSpecificRefs =
            await prisma.referenceAsset.findMany({
                where: { jobId, adId: baseAdId },
                orderBy: { createdAt: "asc" },
                select: {
                    filePath: true,
                    originalName: true,
                    mimeType: true,
                },
            });

        const refsToCopy =
            baseAdSpecificRefs.length > 0
                ? baseAdSpecificRefs
                : await prisma.referenceAsset.findMany({
                      where: { jobId, adId: null },
                      orderBy: { createdAt: "asc" },
                      select: {
                          filePath: true,
                          originalName: true,
                          mimeType: true,
                      },
                  });

        if (refsToCopy.length > 0) {
            const newAds = await prisma.ad.findMany({
                where: {
                    jobId,
                    parentAdId: baseAdId,
                    adNumber: {
                        gte: startAdNumber,
                        lt: startAdNumber + safeCount,
                    },
                },
                select: { id: true },
            });

            const data = newAds.flatMap((newAd) =>
                refsToCopy.map((ref) => ({
                    jobId,
                    adId: newAd.id,
                    filePath: ref.filePath,
                    originalName: ref.originalName,
                    mimeType: ref.mimeType,
                }))
            );

            if (data.length > 0) {
                await prisma.referenceAsset.createMany({ data });
            }
        }
    }

    redirect(`/jobs/${jobId}`);
}

// --- Save a generated ad into the memory-bank tables ---
async function saveAdToMemory(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const adId = formData.get("adId")?.toString();
    const memoryNotes = String(formData.get("memoryNotes") || "").trim();
    const markWinner = formData.get("markWinner") ? true : false;

    if (!jobId || !adId) throw new Error("Missing jobId or adId");

    const job = await prisma.job.findUnique({ where: { id: jobId } });
    if (!job) throw new Error("Job not found");

    const ad = await prisma.ad.findUnique({ where: { id: adId } });
    if (!ad?.sourceBlock) throw new Error("Ad missing sourceBlock");

    type AdTabSource = {
        angle?: string;
        hook?: string;
        primaryText?: string;
        headline?: string;
        cta?: string;
        visualPrompt?: string;
    };

    const source = tryParseJson(ad.sourceBlock) as AdTabSource | null;
    if (!source || typeof source !== "object") {
        throw new Error("Bad ad.sourceBlock JSON");
    }

    const marketType = "donation";
    const preferredCategoryName = "Impact Angles";

    const preferredCategory = await prisma.swipeCategory.findUnique({
        where: {
            name_marketType: {
                name: preferredCategoryName,
                marketType,
            },
        },
    });

    const fallbackCategory = preferredCategory
        ? preferredCategory
        : await prisma.swipeCategory.findFirst({ where: { marketType } });

    if (!fallbackCategory) throw new Error("No swipe categories found for this marketType");

    const swipeTitle =
        (typeof source.headline === "string" && source.headline.trim()) ||
        (typeof source.angle === "string" && source.angle.trim()) ||
        `Generated ad ${ad.adNumber}`;

    await prisma.swipeEntry.create({
        data: {
            title: swipeTitle,
            marketType,
            categoryId: fallbackCategory.id,
            hook:
                typeof source.hook === "string" ? source.hook : undefined,
            angle:
                typeof source.angle === "string" ? source.angle : undefined,
            concept:
                typeof source.headline === "string" && source.headline.trim()
                    ? source.headline
                    : typeof source.primaryText === "string" &&
                        source.primaryText.trim()
                      ? source.primaryText
                      : undefined,
            copy:
                typeof source.primaryText === "string" && source.primaryText.trim()
                    ? source.primaryText
                    : undefined,
            cta:
                typeof source.cta === "string" ? source.cta : undefined,
            visualDirection:
                typeof source.visualPrompt === "string"
                    ? source.visualPrompt
                    : undefined,
            platform: job.platform || undefined,
            funnelStage: job.funnelStage || undefined,
            tags: [
                "generated",
                job.creativeMode || undefined,
                job.adMixStrategy || undefined,
                markWinner ? "winner" : undefined,
            ]
                .filter(Boolean)
                .join(","),
            notes:
                memoryNotes ||
                `Saved from Ad ${ad.adNumber} (${job.id}).`,
        },
    });

    if (markWinner) {
        await prisma.ad.update({
            where: { id: adId },
            data: { isWinner: true },
        });
    }

    redirect(`/jobs/${jobId}`);
}

// --- Image generation stage (per ad) ---
async function generateAdImages(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const adId = formData.get("adId")?.toString();
    const adAspectRatioRaw = formData.get("adAspectRatio")?.toString();
    const adAspectRatio: "1:1" | "9:16" =
        adAspectRatioRaw === "9:16" ? "9:16" : "1:1";

    if (!jobId || !adId) throw new Error("Missing jobId or adId");

    const ad = await prisma.ad.findUnique({
        where: { id: adId },
    });

    if (!ad) throw new Error("Ad not found");

    let prompt = (ad.editedPrompt || ad.sourceBlock || "").trim();
    if (!prompt) throw new Error("No prompt available");

    // Donation TEMPLATE 6 (KLING VIDEO READY) stores BOTH prompts in `visualPrompt`
    // in a single-line format. Kie image generation must use only the KIE portion.
    if (
        prompt.includes("KIE_IMAGE_PROMPT:") &&
        prompt.includes("|| KLING_ANIMATION_PROMPT:")
    ) {
        const afterKie = prompt.split("KIE_IMAGE_PROMPT:")[1] || "";
        const kiePart = afterKie.split("|| KLING_ANIMATION_PROMPT:")[0] || "";
        prompt = kiePart.trim();
    }

    // Prefer ad-specific references. If none exist, fall back to shared job references.
    const adReferenceAssets = await prisma.referenceAsset.findMany({
        where: { jobId, adId },
        orderBy: { createdAt: "asc" },
    });

    const referenceAssets =
        adReferenceAssets.length > 0
            ? adReferenceAssets
            : await prisma.referenceAsset.findMany({
                  where: { jobId, adId: null },
                  orderBy: { createdAt: "asc" },
              });

    const referenceImages = referenceAssets
        .map((asset) => asset.filePath)
        .filter(Boolean);

    console.log("[generateAdImages]", {
        jobId,
        adId,
        referenceCount: referenceImages.length,
        used: adReferenceAssets.length > 0 ? "ad" : "job_shared",
    });

    await prisma.ad.update({
        where: { id: adId },
        data: { status: "generating_images" },
    });

    try {
        const result = await generateImageWithKie(
            prompt,
            referenceImages,
            adAspectRatio
        );
        const urls = extractImageUrlsFromResult(result);

        await prisma.image.deleteMany({
            where: { adId },
        });

        if (urls.length > 0) {
            await prisma.image.createMany({
                data: urls.map((url) => ({
                    adId,
                    url,
                    prompt,
                })),
            });
        }

        await prisma.ad.update({
            where: { id: adId },
            data: {
                status: "images_generated",
                kieResult: JSON.stringify(result, null, 2),
            },
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        await prisma.ad.update({
            where: { id: adId },
            data: {
                status: "kie_error",
                kieResult: `Kie generation failed:\n\n${message}`,
            },
        });
    }

    redirect(`/jobs/${jobId}`);
}

// --- Product reference images (shared across all ads) ---
async function uploadProductReferenceFilesForAllAds(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    if (!jobId) throw new Error("Missing jobId");

    const rawFiles = formData.getAll("referenceFiles");
    const files = rawFiles.filter(
        (item): item is File =>
            !!item &&
            typeof (item as any).size === "number" &&
            (item as any).size > 0
    );

    if (files.length === 0) redirect(`/jobs/${jobId}`);

    const uploaded = await uploadReferenceFilesToKie(files);

    // Replace shared reference images so every ad uses the latest set.
    await prisma.referenceAsset.deleteMany({
        where: { jobId, adId: null },
    });

    await prisma.referenceAsset.createMany({
        data: uploaded.map((file) => ({
            jobId,
            adId: null,
            filePath: file.filePath,
            originalName: file.originalName,
            mimeType: file.mimeType,
        })),
    });

    console.log("[uploadProductReferenceFilesForAllAds]", {
        jobId,
        savedReferences: uploaded.length,
    });

    redirect(`/jobs/${jobId}`);
}

// --- Ad-specific reference images (used by Generate Image for that tab) ---
async function uploadReferenceFilesForAd(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const adId = formData.get("adId")?.toString();
    if (!jobId || !adId) throw new Error("Missing jobId or adId");

    const rawFiles = formData.getAll("referenceFiles");
    const files = rawFiles.filter(
        (item): item is File =>
            !!item &&
            typeof (item as any).size === "number" &&
            (item as any).size > 0
    );

    if (files.length === 0) redirect(`/jobs/${jobId}`);

    const uploaded = await uploadReferenceFilesToKie(files);

    // Replace references for this specific ad.
    await prisma.referenceAsset.deleteMany({
        where: { jobId, adId },
    });

    await prisma.referenceAsset.createMany({
        data: uploaded.map((file) => ({
            jobId,
            adId,
            filePath: file.filePath,
            originalName: file.originalName,
            mimeType: file.mimeType,
        })),
    });

    console.log("[uploadReferenceFilesForAd]", {
        jobId,
        adId,
        savedReferences: uploaded.length,
    });

    redirect(`/jobs/${jobId}`);
}

